class Solution:
    def maxDepthAfterSplit(self, seq: str) -> List[int]:
        answer = []
        depth = 0
        for char in seq:
            if char == '(':
                depth += 1
                answer.append(0 if depth % 2 == 0 else 1)
            else:
                answer.append(0 if depth % 2 == 0 else 1)
                depth -= 1
        return answer

